        A constrained width makes horizontal reading comfortable and focuses the user beautifully.
      */}
      <div style={{ maxWidth: '860px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '3rem' }}>
        
        {/* WELCOME BANNER */}
        <motion.div 
