import React, { useState, useEffect } from 'react';
import { Outlet, Link, useLocation, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  Home, Activity, Bell, User, Users, Briefcase, 
  BookOpen, Edit3, Award, Calendar, MessageSquare, Settings, Menu, X, LogOut
} from 'lucide-react';
import nestMainLogo from '../assets/nest_logo.png';
import { getUser, authApi, type AuthUser } from '../services/api';
import '../App.css'; // Just re-using default CSS, we will add layout styles below inline or in App.css

const MainLayout: React.FC = () => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const location = useLocation();
  const navigate = useNavigate();
  const [user, setUserData] = useState<AuthUser | null>(null);

  useEffect(() => {
    const currentUser = getUser() as unknown as AuthUser;
    if (currentUser) {
      setUserData(currentUser);
    }
  }, [location.pathname]);

  const handleLogout = () => {
    authApi.logout();
    navigate('/login');
  };

  const menuItems = [
    { section: 'Dashboard', items: [
      { name: 'Overview', path: '/dashboard', icon: <Home size={18} /> },
      { name: 'Activity Feed', path: '/dashboard/activity', icon: <Activity size={18} /> },
      { name: 'Notifications', path: '/notifications', icon: <Bell size={18} /> },
    ]},
    { section: 'Profile', items: [
      { name: 'View Profile', path: '/profile', icon: <User size={18} /> },
      { name: 'Edit Profile', path: '/profile/edit', icon: <Edit3 size={18} /> },
    ]},
    { section: 'Networking', items: [
      { name: 'Directory', path: '/networking', icon: <Users size={18} /> },
      { name: 'Connections', path: '/networking/connections', icon: <Users size={18} /> },
    ]},
    { section: 'Jobs', items: [
      { name: 'Job Listings', path: '/jobs', icon: <Briefcase size={18} /> },
      { name: 'My Applications', path: '/jobs/applications', icon: <Briefcase size={18} /> },
      { name: 'Recommended Jobs', path: '/jobs/recommended', icon: <Briefcase size={18} /> },
    ]},
    { section: 'Learning', items: [
      { name: 'Courses', path: '/courses', icon: <BookOpen size={18} /> },
      { name: 'My Courses', path: '/courses/my-courses', icon: <BookOpen size={18} /> },
    ]},
    { section: 'Assessments', items: [
      { name: 'Quizzes', path: '/assessments/quiz', icon: <Edit3 size={18} /> },
      { name: 'Analytics', path: '/assessments/analytics', icon: <Activity size={18} /> },
    ]},
    { section: 'Gamification', items: [
      { name: 'Points Overview', path: '/gamification', icon: <Award size={18} /> },
      { name: 'Leaderboard', path: '/gamification/leaderboard', icon: <Award size={18} /> },
    ]},
    { section: 'Events', items: [
      { name: 'Events Listing', path: '/events', icon: <Calendar size={18} /> },
      { name: 'My Events', path: '/events/my-events', icon: <Calendar size={18} /> },
    ]},
    { section: 'Social', items: [
      { name: 'Feed', path: '/social/feed', icon: <MessageSquare size={18} /> },
    ]},
    { section: 'Settings', items: [
      { name: 'Account Settings', path: '/settings', icon: <Settings size={18} /> },
    ]}
  ];

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#f4f6f8', overflow: 'hidden' }}>
      {/* Sidebar */}
      <motion.div 
        initial={{ width: 260 }}
        animate={{ width: sidebarOpen ? 260 : 80 }}
        transition={{ duration: 0.3 }}
        style={{ 
          background: '#ffffff', 
          borderRight: '1px solid #eaeaea', 
          display: 'flex', 
          flexDirection: 'column',
          zIndex: 100
        }}
        className="sidebar"
      >
        <div style={{ padding: '20px', display: 'flex', alignItems: 'center', justifyContent: sidebarOpen ? 'space-between' : 'center', borderBottom: '1px solid #eaeaea' }}>
          {sidebarOpen && (
             <img src={nestMainLogo} alt="NeST Digital" style={{ height: '32px' }} />
          )}
          <button onClick={() => setSidebarOpen(!sidebarOpen)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#333' }}>
            {sidebarOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
        
        <div style={{ flex: 1, overflowY: 'auto', padding: '10px 0' }} className="custom-scrollbar">
          {menuItems.map((group, i) => (
             <div key={i} style={{ marginBottom: '15px' }}>
               {sidebarOpen && <div style={{ padding: '0 20px', fontSize: '11px', fontWeight: 'bold', color: '#999', textTransform: 'uppercase', marginBottom: '8px' }}>{group.section}</div>}
               {group.items.map((item, j) => {
                 const isActive = location.pathname === item.path;
                 return (
                   <Link 
                     key={j} 
                     to={item.path}
                     style={{
                       display: 'flex',
                       alignItems: 'center',
                       padding: '10px 20px',
                       textDecoration: 'none',
                       color: isActive ? '#d32f2f' : '#333',
                       background: isActive ? '#fff1f1' : 'transparent',
                       borderRight: isActive ? '3px solid #d32f2f' : '3px solid transparent',
                       transition: 'all 0.2s'
                     }}
                   >
                     <span style={{ marginRight: sidebarOpen ? '15px' : '0', color: isActive ? '#d32f2f' : '#666' }}>{item.icon}</span>
                     {sidebarOpen && <span style={{ fontSize: '14px', fontWeight: isActive ? 600 : 400 }}>{item.name}</span>}
                   </Link>
                 )
               })}
             </div>
          ))}
        </div>
        
        <div style={{ padding: '20px', borderTop: '1px solid #eaeaea' }}>
          <button 
            onClick={handleLogout} 
            style={{ display: 'flex', alignItems: 'center', color: '#666', background: 'none', border: 'none', padding: 0, cursor: 'pointer', justifyContent: sidebarOpen ? 'flex-start' : 'center', width: '100%', fontSize: '16px' }}
          >
            <LogOut size={20} style={{ marginRight: sidebarOpen ? '10px' : '0' }} />
            {sidebarOpen && <span>Logout</span>}
          </button>
        </div>
      </motion.div>

      {/* Main Content Area */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        {/* Header */}
        <header style={{ height: '70px', background: '#fff', borderBottom: '1px solid #eaeaea', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 30px' }}>
           <h2 style={{ fontSize: '18px', margin: 0, color: '#333' }}>NeST Portal</h2>
           <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
              <Bell size={20} color="#666" style={{ cursor: 'pointer' }} />
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer' }}>
                {user?.profile_picture ? (
                  <img src={user.profile_picture} alt={user.full_name} style={{ width: '36px', height: '36px', borderRadius: '50%', objectFit: 'cover' }} />
                ) : (
                  <div style={{ width: '36px', height: '36px', borderRadius: '50%', background: '#d32f2f', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold' }}>
                    {user ? user.full_name.charAt(0).toUpperCase() : 'U'}
                  </div>
                )}
                <div style={{ display: 'flex', flexDirection: 'column' }}>
                  <span style={{ fontSize: '14px', fontWeight: 600, color: '#333' }}>{user ? user.full_name : 'Guest'}</span>
                  <span style={{ fontSize: '12px', color: '#888' }}>{user ? user.user_type : 'User'}</span>
                </div>
              </div>
           </div>
        </header>

        {/* Page Content */}
        <div id="main-content-scroll" className="custom-scrollbar" style={{ flex: 1, overflowY: 'auto', padding: '30px', position: 'relative', scrollBehavior: 'smooth' }}>
          <Outlet />
        </div>
      </div>
    </div>
  );
};

export default MainLayout;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Briefcase, MapPin, Clock, CheckCircle2, XCircle, AlertCircle, Eye, FileText, ChevronDown, ChevronUp, Filter, Search } from 'lucide-react';
import { Link } from 'react-router-dom';

// Status type
type ApplicationStatus = 'Under Review' | 'Shortlisted' | 'Interview Scheduled' | 'Offered' | 'Rejected' | 'Withdrawn';

interface Application {
  id: string;
  jobId: string;
  title: string;
  department: string;
  location: string;
  type: string;
  appliedDate: string;
  status: ApplicationStatus;
  lastUpdated: string;
  interviewDate?: string;
  notes?: string;
}

const MOCK_APPLICATIONS: Application[] = [
  {
    id: 'app-1',
    jobId: '1',
    title: 'Senior Full Stack Developer',
    department: 'Engineering',
    location: 'Kochi, Kerala (Hybrid)',
    type: 'Full-time',
    appliedDate: '2026-03-23',
    status: 'Interview Scheduled',
    lastUpdated: '2026-03-25',
    interviewDate: '2026-03-28',
    notes: 'Technical round with the Engineering Lead. Please prepare system design topics.'
  },
  {
    id: 'app-2',
    jobId: '3',
    title: 'Cloud Infrastructure Architect',
    department: 'IT Infrastructure',
    location: 'Remote',
    type: 'Contract',
    appliedDate: '2026-03-20',
    status: 'Shortlisted',
    lastUpdated: '2026-03-24',
    notes: 'Profile under detailed review by the hiring manager.'
  },
  {
    id: 'app-3',
    jobId: '5',
    title: 'Frontend React Developer',
    department: 'Engineering',
    location: 'Kochi, Kerala (Hybrid)',
    type: 'Full-time',
    appliedDate: '2026-03-18',
    status: 'Under Review',
    lastUpdated: '2026-03-18'
  },
  {
    id: 'app-4',
    jobId: '4',
    title: 'Product Manager',
    department: 'Product',
    location: 'Dubai, UAE (On-site)',
    type: 'Full-time',
    appliedDate: '2026-03-10',
    status: 'Offered',
    lastUpdated: '2026-03-22',
    notes: 'Congratulations! An offer letter has been sent to your registered email address.'
  },
  {
    id: 'app-5',
    jobId: '2',
    title: 'Lead UX/UI Designer',
    department: 'Design',
    location: 'Trivandrum, Kerala (On-site)',
    type: 'Full-time',
    appliedDate: '2026-03-05',
    status: 'Rejected',
    lastUpdated: '2026-03-15',
    notes: 'We appreciate your interest. Unfortunately, we moved forward with another candidate.'
  }
];

const STATUS_CONFIG: Record<ApplicationStatus, { color: string; bg: string; border: string; icon: React.ReactNode }> = {
  'Under Review': { color: '#e67700', bg: '#fff9db', border: '#ffd43b', icon: <Clock size={16} /> },
  'Shortlisted': { color: '#1971c2', bg: '#e7f5ff', border: '#74c0fc', icon: <Eye size={16} /> },
  'Interview Scheduled': { color: '#7048e8', bg: '#f3f0ff', border: '#b197fc', icon: <AlertCircle size={16} /> },
  'Offered': { color: '#2b8a3e', bg: '#ebfbee', border: '#69db7c', icon: <CheckCircle2 size={16} /> },
  'Rejected': { color: '#c92a2a', bg: '#fff5f5', border: '#ffa8a8', icon: <XCircle size={16} /> },
  'Withdrawn': { color: '#868e96', bg: '#f8f9fa', border: '#dee2e6', icon: <XCircle size={16} /> }
};

const ALL_STATUSES: ApplicationStatus[] = ['Under Review', 'Shortlisted', 'Interview Scheduled', 'Offered', 'Rejected', 'Withdrawn'];

const MyApplications: React.FC = () => {
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchTerm, setSearchTerm] = useState('');

  const filteredApps = MOCK_APPLICATIONS.filter(app => {
    const matchesStatus = filterStatus === 'All' || app.status === filterStatus;
    const matchesSearch = app.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          app.department.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const statusCounts = MOCK_APPLICATIONS.reduce((acc, app) => {
    acc[app.status] = (acc[app.status] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const formatDate = (dateStr: string) => {
    return new Date(dateStr).toLocaleDateString('en-IN', {
      day: 'numeric', month: 'short', year: 'numeric'
    });
  };

  const getTimelineSteps = (status: ApplicationStatus) => {
    const steps = ['Applied', 'Under Review', 'Shortlisted', 'Interview', 'Decision'];
    const statusMap: Record<ApplicationStatus, number> = {
      'Under Review': 1,
      'Shortlisted': 2,
      'Interview Scheduled': 3,
      'Offered': 4,
      'Rejected': 4,
      'Withdrawn': -1
    };
    const activeStep = statusMap[status];
    return { steps, activeStep };
  };

  return (
    <div style={{ minHeight: '100vh', padding: '4rem 2rem', background: '#ffffff', color: '#1a1a1a', fontFamily: 'Inter, sans-serif' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto' }}>

        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          style={{ marginBottom: '2.5rem' }}
        >
          <Link
            to="/jobs"
            style={{ display: 'inline-flex', alignItems: 'center', color: '#666666', marginBottom: '1.5rem', fontSize: '0.9rem', transition: 'color 0.3s', textDecoration: 'none' }}
            onMouseEnter={(e) => { e.currentTarget.style.color = 'var(--primary)'; }}
            onMouseLeave={(e) => { e.currentTarget.style.color = '#666666'; }}
          >
            <ArrowLeft size={16} style={{ marginRight: '0.5rem' }} /> Back to Job Listings
          </Link>
          <h1 style={{ fontSize: '2.8rem', marginBottom: '0.5rem', color: '#1a1a1a' }}>
            My <span style={{ color: 'var(--primary)' }}>Applications</span>
          </h1>
          <p style={{ fontSize: '1.05rem', color: '#4a4a4a', maxWidth: '600px' }}>
            Track the status of all your job applications. Stay updated on interviews and offers.
          </p>
        </motion.div>

        {/* Stats Cards */}
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.1 }}
          style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))', gap: '1rem', marginBottom: '2.5rem' }}
        >
          {[
            { label: 'Total', count: MOCK_APPLICATIONS.length, color: '#1a1a1a', bg: '#f8f9fa' },
            { label: 'In Progress', count: (statusCounts['Under Review'] || 0) + (statusCounts['Shortlisted'] || 0) + (statusCounts['Interview Scheduled'] || 0), color: '#1971c2', bg: '#e7f5ff' },
            { label: 'Offered', count: statusCounts['Offered'] || 0, color: '#2b8a3e', bg: '#ebfbee' },
            { label: 'Rejected', count: statusCounts['Rejected'] || 0, color: '#c92a2a', bg: '#fff5f5' },
          ].map((stat) => (
            <div
              key={stat.label}
              style={{
                background: stat.bg,
                borderRadius: '12px',
                padding: '1.2rem 1.5rem',
                border: '1px solid #e9ecef',
                textAlign: 'center'
              }}
            >
              <p style={{ fontSize: '2rem', fontWeight: 800, color: stat.color, margin: '0 0 0.2rem 0' }}>{stat.count}</p>
              <p style={{ fontSize: '0.85rem', color: '#6c757d', fontWeight: 500, margin: 0 }}>{stat.label}</p>
            </div>
          ))}
        </motion.div>

        {/* Filter & Search Bar */}
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.15 }}
          style={{
            background: '#f8f9fa',
            border: '1px solid #e9ecef',
            borderRadius: '14px',
            padding: '1.2rem 1.5rem',
            marginBottom: '2rem',
            display: 'flex',
            flexWrap: 'wrap',
            gap: '1rem',
            alignItems: 'center'
          }}
        >
          <div style={{ flex: '1 1 250px', position: 'relative' }}>
            <Search size={18} style={{ position: 'absolute', left: '0.8rem', top: '50%', transform: 'translateY(-50%)', color: '#6c757d' }} />
            <input
              type="text"
              placeholder="Search applications..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={{
                width: '100%',
                padding: '0.75rem 0.75rem 0.75rem 2.5rem',
                borderRadius: '8px',
                border: '1px solid #ced4da',
                background: '#ffffff',
                color: '#1a1a1a',
                fontSize: '0.95rem',
                outline: 'none',
                boxSizing: 'border-box'
              }}
            />
          </div>
          <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap', alignItems: 'center' }}>
            <Filter size={16} color="#6c757d" />
            {['All', ...ALL_STATUSES.filter(s => statusCounts[s])].map(status => (
              <button
                key={status}
                onClick={() => setFilterStatus(status)}
                style={{
                  padding: '0.4rem 0.9rem',
                  borderRadius: '20px',
                  fontSize: '0.82rem',
                  fontWeight: 500,
                  border: `1px solid ${filterStatus === status ? 'var(--primary)' : '#ced4da'}`,
                  background: filterStatus === status ? 'var(--primary)' : '#ffffff',
                  color: filterStatus === status ? 'white' : '#4a4a4a',
                  cursor: 'pointer',
                  transition: 'all 0.2s'
                }}
              >
                {status}
              </button>
            ))}
          </div>
        </motion.div>

        {/* Applications List */}
        <AnimatePresence mode="popLayout">
          {filteredApps.length > 0 ? (
            filteredApps.map((app, index) => {
              const config = STATUS_CONFIG[app.status];
              const isExpanded = expandedId === app.id;
              const { steps, activeStep } = getTimelineSteps(app.status);

              return (
                <motion.div
                  key={app.id}
                  initial={{ opacity: 0, y: 15 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -10 }}
                  transition={{ duration: 0.35, delay: index * 0.05 }}
                  layout
                  style={{
                    background: '#ffffff',
                    border: `1px solid ${isExpanded ? config.border : '#e9ecef'}`,
                    borderRadius: '16px',
                    padding: '1.5rem 1.8rem',
                    marginBottom: '1rem',
                    cursor: 'pointer',
                    transition: 'all 0.3s ease',
                    boxShadow: isExpanded ? `0 8px 24px ${config.bg}` : '0 2px 6px rgba(0,0,0,0.02)'
                  }}
                  onClick={() => setExpandedId(isExpanded ? null : app.id)}
                  onMouseEnter={(e) => { if (!isExpanded) { e.currentTarget.style.boxShadow = '0 6px 16px rgba(0,0,0,0.06)'; e.currentTarget.style.borderColor = '#dee2e6'; } }}
                  onMouseLeave={(e) => { if (!isExpanded) { e.currentTarget.style.boxShadow = '0 2px 6px rgba(0,0,0,0.02)'; e.currentTarget.style.borderColor = '#e9ecef'; } }}
                >
                  {/* Main Row */}
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem' }}>
                    <div style={{ flex: '1 1 300px' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', marginBottom: '0.5rem' }}>
                        <span style={{ color: 'var(--primary)', fontSize: '0.78rem', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.5px' }}>{app.department}</span>
                        <span style={{ color: '#dee2e6' }}>ΓÇó</span>
                        <span style={{ color: '#6c757d', fontSize: '0.78rem' }}>{app.type}</span>
                      </div>
                      <h3 style={{ fontSize: '1.2rem', fontWeight: 700, color: '#1a1a1a', margin: '0 0 0.6rem 0' }}>{app.title}</h3>
                      <div style={{ display: 'flex', flexWrap: 'wrap', gap: '1rem' }}>
                        <span style={{ display: 'flex', alignItems: 'center', gap: '0.35rem', color: '#6c757d', fontSize: '0.85rem' }}>
                          <MapPin size={14} color="var(--primary)" /> {app.location}
                        </span>
                        <span style={{ display: 'flex', alignItems: 'center', gap: '0.35rem', color: '#6c757d', fontSize: '0.85rem' }}>
                          <FileText size={14} color="var(--primary)" /> Applied {formatDate(app.appliedDate)}
                        </span>
                      </div>
                    </div>

                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                      {/* Status Badge */}
                      <div style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: '0.4rem',
                        padding: '0.45rem 1rem',
                        borderRadius: '20px',
                        background: config.bg,
                        border: `1px solid ${config.border}`,
                        color: config.color,
                        fontWeight: 600,
                        fontSize: '0.82rem'
                      }}>
                        {config.icon}
                        {app.status}
                      </div>

                      {/* Expand Toggle */}
                      <motion.div
                        animate={{ rotate: isExpanded ? 180 : 0 }}
                        transition={{ duration: 0.2 }}
                        style={{ color: '#adb5bd', display: 'flex' }}
                      >
                        <ChevronDown size={20} />
                      </motion.div>
                    </div>
                  </div>

                  {/* Expanded Details */}
                  <AnimatePresence>
                    {isExpanded && (
                      <motion.div
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        transition={{ duration: 0.3 }}
                        style={{ overflow: 'hidden' }}
                        onClick={(e) => e.stopPropagation()}
                      >
                        <div style={{ borderTop: '1px solid #e9ecef', marginTop: '1.5rem', paddingTop: '1.5rem' }}>

                          {/* Progress Timeline */}
                          <div style={{ marginBottom: '1.5rem' }}>
                            <p style={{ fontSize: '0.82rem', fontWeight: 600, color: '#6c757d', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: '1rem' }}>Application Progress</p>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0' }}>
                              {steps.map((step, i) => {
                                const isActive = i <= activeStep;
                                const isCurrent = i === activeStep;
                                const isRejected = app.status === 'Rejected' && i === activeStep;
                                const dotColor = isRejected ? '#c92a2a' : isActive ? 'var(--primary)' : '#dee2e6';
                                const lineColor = isActive && i < activeStep ? 'var(--primary)' : '#dee2e6';

                                return (
                                  <div key={step} style={{ display: 'flex', alignItems: 'center', flex: i < steps.length - 1 ? 1 : 'none' }}>
                                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', position: 'relative' }}>
                                      <div style={{
                                        width: isCurrent ? '14px' : '10px',
                                        height: isCurrent ? '14px' : '10px',
                                        borderRadius: '50%',
                                        background: dotColor,
                                        border: isCurrent ? `3px solid ${isRejected ? '#ffa8a8' : 'rgba(200,16,46,0.2)'}` : 'none',
                                        transition: 'all 0.3s'
                                      }} />
                                      <span style={{
                                        position: 'absolute',
                                        top: '22px',
                                        fontSize: '0.7rem',
                                        color: isActive ? '#4a4a4a' : '#adb5bd',
                                        fontWeight: isCurrent ? 700 : 500,
                                        whiteSpace: 'nowrap'
                                      }}>
                                        {step}
                                      </span>
                                    </div>
                                    {i < steps.length - 1 && (
                                      <div style={{ flex: 1, height: '2px', background: lineColor, transition: 'background 0.3s' }} />
                                    )}
                                  </div>
                                );
                              })}
                            </div>
                          </div>

                          {/* Additional Info */}
                          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '1.5rem', marginTop: '2.5rem' }}>
                            <div style={{ flex: '1 1 200px' }}>
                              <p style={{ fontSize: '0.78rem', fontWeight: 600, color: '#868e96', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: '0.3rem' }}>Last Updated</p>
                              <p style={{ color: '#1a1a1a', fontWeight: 500, fontSize: '0.95rem' }}>{formatDate(app.lastUpdated)}</p>
                            </div>
                            {app.interviewDate && (
                              <div style={{ flex: '1 1 200px' }}>
                                <p style={{ fontSize: '0.78rem', fontWeight: 600, color: '#868e96', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: '0.3rem' }}>Interview Date</p>
                                <p style={{ color: '#7048e8', fontWeight: 600, fontSize: '0.95rem' }}>{formatDate(app.interviewDate)}</p>
                              </div>
                            )}
                          </div>

                          {/* Notes */}
                          {app.notes && (
                            <div style={{ background: config.bg, border: `1px solid ${config.border}`, borderRadius: '10px', padding: '1rem 1.2rem', marginTop: '1rem' }}>
                              <p style={{ fontSize: '0.82rem', fontWeight: 600, color: config.color, marginBottom: '0.3rem' }}>
                                {config.icon} Note from Recruiter
                              </p>
                              <p style={{ color: '#4a4a4a', fontSize: '0.9rem', lineHeight: 1.6, margin: 0 }}>{app.notes}</p>
                            </div>
                          )}

                          {/* Action Buttons */}
                          <div style={{ display: 'flex', gap: '0.75rem', marginTop: '1.5rem', flexWrap: 'wrap' }}>
                            <Link
                              to={`/jobs/${app.jobId}`}
                              style={{
                                padding: '0.6rem 1.2rem',
                                borderRadius: '8px',
                                background: '#ffffff',
                                border: '1px solid #ced4da',
                                color: '#4a4a4a',
                                fontSize: '0.88rem',
                                fontWeight: 600,
                                textDecoration: 'none',
                                display: 'inline-flex',
                                alignItems: 'center',
                                gap: '0.4rem',
                                transition: 'all 0.2s'
                              }}
                              onMouseEnter={(e) => { e.currentTarget.style.background = '#f8f9fa'; e.currentTarget.style.borderColor = 'var(--primary)'; e.currentTarget.style.color = 'var(--primary)'; }}
                              onMouseLeave={(e) => { e.currentTarget.style.background = '#ffffff'; e.currentTarget.style.borderColor = '#ced4da'; e.currentTarget.style.color = '#4a4a4a'; }}
                            >
                              <Briefcase size={15} /> View Job Details
                            </Link>
                            {(app.status !== 'Rejected' && app.status !== 'Withdrawn') && (
                              <button
                                style={{
                                  padding: '0.6rem 1.2rem',
                                  borderRadius: '8px',
                                  background: '#ffffff',
                                  border: '1px solid #ffa8a8',
                                  color: '#c92a2a',
                                  fontSize: '0.88rem',
                                  fontWeight: 600,
                                  cursor: 'pointer',
                                  transition: 'all 0.2s'
                                }}
                                onMouseEnter={(e) => { e.currentTarget.style.background = '#fff5f5'; }}
                                onMouseLeave={(e) => { e.currentTarget.style.background = '#ffffff'; }}
                              >
                                Withdraw Application
                              </button>
                            )}
                          </div>
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </motion.div>
              );
            })
          ) : (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              style={{
                textAlign: 'center',
                padding: '4rem 2rem',
                background: '#ffffff',
                borderRadius: '16px',
                border: '1px solid #e9ecef',
                boxShadow: '0 4px 6px rgba(0,0,0,0.02)'
              }}
            >
              <div style={{ background: '#f8f9fa', display: 'inline-block', padding: '1.5rem', borderRadius: '50%', marginBottom: '1rem' }}>
                <Briefcase size={40} color="#adb5bd" />
              </div>
              <h3 style={{ fontSize: '1.5rem', marginBottom: '0.5rem', color: '#1a1a1a' }}>No applications found</h3>
              <p style={{ color: '#6c757d', marginBottom: '1.5rem' }}>
                {filterStatus !== 'All' || searchTerm
                  ? 'Try changing your filters to see more results.'
                  : "You haven't applied to any jobs yet. Explore opportunities and get started!"}
              </p>
              {filterStatus !== 'All' || searchTerm ? (
                <button
                  onClick={() => { setFilterStatus('All'); setSearchTerm(''); }}
                  style={{ background: '#ffffff', color: '#1a1a1a', border: '1px solid #ced4da', padding: '0.8rem 1.5rem', borderRadius: '8px', cursor: 'pointer', fontWeight: 500 }}
                >
                  Clear Filters
                </button>
              ) : (
                <Link
                  to="/jobs"
                  style={{
                    background: 'var(--primary)',
                    color: 'white',
                    padding: '0.8rem 2rem',
                    borderRadius: '8px',
                    fontWeight: 600,
                    textDecoration: 'none',
                    display: 'inline-block',
                    transition: 'background 0.3s'
                  }}
                >
                  Browse Job Listings
                </Link>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default MyApplications;

