                                    <Award size={15} /> Download Certificate
                                  </button>
                                )}
                              </>
                            ) : (
                              <>
                                <button
                                  onClick={() => navigate(`/courses/${course.courseId}`)}
                                  style={{
                                    padding: '0.6rem 1.2rem',
                                    borderRadius: '8px',
                                    background: 'var(--primary)',
                                    border: '1px solid var(--primary)',
                                    color: 'white',
                                    fontSize: '0.88rem',
                                    fontWeight: 600,
                                    cursor: 'pointer',
                                    display: 'inline-flex',
                                    alignItems: 'center',
