              <Calendar size={14} color={nestNavy} /> Event Governance <span>{'>'}</span> Hosting
            </div>
            <h1 style={{ fontSize: '24px', fontWeight: 800, color: '#1e293b', margin: 0 }}>Create Strategic Event</h1>
