        </div>

        <div style={{ display: 'flex', gap: '16px' }}>
          <button style={{ padding: '12px 24px', borderRadius: '14px', background: '#f1f5f9', color: '#475569', fontWeight: 700, border: 'none', cursor: 'pointer' }}>
            Save Draft
          </button>
          <button 
            onClick={() => console.log('Publishing:', formData)}
            style={{ 
              display: 'flex', 
              alignItems: 'center', 
              gap: '10px', 
              padding: '12px 28px', 
              borderRadius: '14px', 
              background: nestNavy, 
              border: 'none',
              color: '#fff', 
