  const getStatusColor = (status: string) => {
    switch (status) {
      case 'Upcoming': return { bg: 'rgba(26, 38, 82, 0.08)', color: nestNavy }; 
      case 'Completed': return { bg: '#dcfce7', color: '#16a34a' };
