import React, { useState, useEffect } from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';
import {
  LayoutDashboard, Users, GraduationCap, School, Briefcase,
  FileText, BarChart3, Settings, LogOut, Bell, Menu, X, ChevronDown, BookOpen, Calendar
} from 'lucide-react';
import nestMainLogo from '../../assets/nest_logo.png';
import { getUser, authApi, type AuthUser } from '../../services/api';
import { useNavigate } from 'react-router-dom';

const AdminLayout: React.FC = () => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const location = useLocation();
  const navigate = useNavigate();

  const [adminUser, setAdminUser] = useState<AuthUser | null>(null);

  useEffect(() => {
    const currentUser = getUser() as unknown as AuthUser;
    if (currentUser) {
      setAdminUser(currentUser);
    }
  }, [location.pathname]);

  const handleLogout = () => {
    authApi.logout();
    navigate('/login');
  };

  const menuItems = [
    { name: 'Dashboard', path: '/admin/dashboard', icon: <LayoutDashboard size={20} /> },
    { name: 'User Management', path: '/admin/users', icon: <Users size={20} /> },
    { name: 'Intern Management', path: '/admin/interns', icon: <GraduationCap size={20} /> },
    { name: 'IV Students', path: '/admin/iv-students', icon: <School size={20} /> },
    { name: 'Job Management', path: '/admin/jobs', icon: <Briefcase size={20} /> },
    { name: 'Applications', path: '/admin/applications', icon: <FileText size={20} /> },
    { name: 'Reports', path: '/admin/reports', icon: <BarChart3 size={20} />, hasSubmenu: true },
    { name: 'Event Management', path: '/admin/events', icon: <Calendar size={20} /> },
    { name: 'Add Courses', path: '/admin/add-courses', icon: <BookOpen size={20} /> },
    { name: 'Settings', path: '/admin/settings', icon: <Settings size={20} /> },
  ];

  /* EXACT NeST LOGO NAVY BLUE: #1A2652 (Approx based on visual matching) */
  const nestNavy = '#1a2652';

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#f8fafc', overflow: 'hidden', fontFamily: "'Inter', sans-serif" }}>
      {/* Sidebar - MATCHING LOGO NAVY */}
      <motion.div
        initial={{ width: 260 }}
        animate={{ width: sidebarOpen ? 260 : 80 }}
        transition={{ duration: 0.3, ease: 'easeInOut' }}
        style={{
          background: nestNavy, /* EXACT LOGO NAVY MATCH */
          display: 'flex',
          flexDirection: 'column',
          zIndex: 100,
          color: '#e2e8f0',
          boxShadow: '4px 0 10px rgba(0,0,0,0.05)'
        }}
      >
        <div style={{
          padding: '20px 16px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: sidebarOpen ? 'space-between' : 'center',
          gap: '12px',
          borderBottom: '1px solid rgba(255,255,255,0.08)'
        }}>
          {sidebarOpen ? (
            <>
              <div style={{
                background: 'rgba(255, 255, 255, 0.95)',
                backdropFilter: 'blur(10px)',
                WebkitBackdropFilter: 'blur(10px)',
                borderRadius: '12px',
                padding: '6px 12px',
                display: 'flex',
                alignItems: 'center',
                boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
                border: '1px solid rgba(255,255,255,0.2)',
                flex: 1
              }}>
                <img src={nestMainLogo} alt="NeST DIGITAL" style={{ height: '28px' }} />
              </div>
              <button
                onClick={() => setSidebarOpen(!sidebarOpen)}
                style={{
                  background: 'rgba(255, 255, 255, 0.15)',
                  backdropFilter: 'blur(10px)',
                  WebkitBackdropFilter: 'blur(10px)',
                  border: '1px solid rgba(255, 255, 255, 0.2)',
                  cursor: 'pointer',
                  color: '#fff',
                  padding: '10px',
                  borderRadius: '12px',
                  display: 'flex',
                  transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)'
                }}
                className="sidebar-toggle-btn"
              >
                <X size={18} />
              </button>
            </>
          ) : (
            <button
              onClick={() => setSidebarOpen(!sidebarOpen)}
              style={{
                background: 'rgba(255, 255, 255, 0.15)',
                backdropFilter: 'blur(10px)',
                WebkitBackdropFilter: 'blur(10px)',
                border: '1px solid rgba(255, 255, 255, 0.2)',
                cursor: 'pointer',
                color: '#fff',
                padding: '12px',
                borderRadius: '14px',
                display: 'flex',
                boxShadow: '0 8px 32px rgba(0, 0, 0, 0.1)',
                transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)'
              }}
              className="sidebar-toggle-btn-closed"
            >
              <Menu size={20} />
            </button>
          )}
        </div>

        <div style={{ flex: 1, overflowY: 'auto', padding: '16px 0' }} className="admin-sidebar-scroll">
          {menuItems.map((item, index) => {
            const isActive = location.pathname.startsWith(item.path);
            return (
              <Link
                key={index}
                to={item.path}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  padding: sidebarOpen ? '14px 24px' : '14px 0',
                  textDecoration: 'none',
                  color: isActive ? '#fff' : 'rgba(255, 255, 255, 0.7)',
                  background: isActive ? 'rgba(255, 255, 255, 0.12)' : 'transparent',
                  transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
                  marginBottom: '2px',
                  justifyContent: sidebarOpen ? 'flex-start' : 'center',
                  position: 'relative'
                }}
              >
                {isActive && !sidebarOpen && (
                  <div style={{ position: 'absolute', left: 0, top: '20%', bottom: '20%', width: '4px', background: '#fff', borderRadius: '0 4px 4px 0' }}></div>
                )}
                <span style={{
                  marginRight: sidebarOpen ? '16px' : '0',
                  color: isActive ? '#fff' : 'inherit',
                  display: 'flex',
                  transition: 'all 0.3s'
                }}>{item.icon}</span>
                {sidebarOpen && (
                  <>
                    <span style={{ fontSize: '14px', fontWeight: isActive ? 700 : 400, flex: 1, letterSpacing: '0.01em' }}>{item.name}</span>
                    {item.hasSubmenu && <ChevronDown size={14} style={{ opacity: 0.5 }} />}
                    {isActive && (
                      <motion.div layoutId="activeInd" style={{ position: 'absolute', left: 0, top: 0, bottom: 0, width: '4px', background: '#fff' }} />
                    )}
                  </>
                )}
              </Link>
            )
          })}
        </div>

        <div style={{ padding: '24px', borderTop: '1px solid rgba(255,255,255,0.08)' }}>
          <button
            onClick={handleLogout}
            style={{
              display: 'flex',
              alignItems: 'center',
              color: 'rgba(255, 255, 255, 0.65)',
              background: 'none',
              border: 'none',
              padding: '10px 0',
              cursor: 'pointer',
              justifyContent: sidebarOpen ? 'flex-start' : 'center',
              width: '100%',
              gap: '16px'
            }}
          >
            <LogOut size={20} />
            {sidebarOpen && <span style={{ fontSize: '14px', fontWeight: 500 }}>Logout</span>}
          </button>
        </div>
      </motion.div>

      {/* Main Content Area */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        {/* Header */}
        <header style={{ height: '72px', background: '#fff', borderBottom: '1px solid #e2e8f0', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 32px', zIndex: 90 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            <h2 style={{
              fontSize: '22px',
              fontWeight: 700,
              color: '#1e293b',
              margin: 0,
              fontFamily: "'Playfair Display', serif",
              letterSpacing: '0.025em'
            }}>
              NeST Admin&nbsp;Portal
            </h2>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '28px' }}>
            <div style={{ position: 'relative', cursor: 'pointer', display: 'flex', padding: '8px', borderRadius: '10px', transition: 'background 0.2s' }} className="hover-highlight">
              <Bell size={22} color="#64748b" />
              <span style={{ position: 'absolute', top: '8px', right: '8px', background: '#ef4444', height: '10px', width: '10px', borderRadius: '50%', border: '2px solid #fff' }}></span>
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', cursor: 'pointer', padding: '4px', borderRadius: '12px' }}>
              <div style={{ position: 'relative' }}>
                {adminUser?.profile_picture ? (
                  <img src={adminUser.profile_picture} alt={adminUser.full_name} style={{ width: '42px', height: '42px', borderRadius: '12px', objectFit: 'cover' }} />
                ) : (
                  <div style={{ width: '42px', height: '42px', borderRadius: '12px', background: nestNavy, color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold', fontSize: '16px' }}>
                    {adminUser ? adminUser.full_name.substring(0, 2).toUpperCase() : 'AD'}
                  </div>
                )}
                <div style={{ position: 'absolute', bottom: '-2px', right: '-2px', width: '12px', height: '12px', background: '#22c55e', borderRadius: '50%', border: '2px solid #fff' }}></div>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column' }}>
                <span style={{ fontSize: '14px', fontWeight: 700, color: '#1e293b' }}>{adminUser ? adminUser.full_name : 'Administrator'}</span>
                <span style={{ fontSize: '12px', color: '#64748b', fontWeight: 500 }}>System Admin</span>
              </div>
              <ChevronDown size={14} color="#64748b" />
            </div>
          </div>
        </header>

        {/* Page Content */}
        <main style={{ flex: 1, overflowY: 'auto', padding: '32px', background: '#f8fafc' }}>
          <Outlet />
        </main>
      </div>
    </div>
  );
};

export default AdminLayout;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  ClipboardSignature, Briefcase, Banknote, ClipboardCheck
} from 'lucide-react';
import { adminApi } from '../../services/api';

const AdminPostJob: React.FC = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    title: '',
    company: '',
    location: '',
    salary: '',
    description: '',
    requirements: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    
    const jobData = {
      ...formData,
      requirements: formData.requirements.split('\n').filter(r => r.trim() !== '')
    };

    const res = await adminApi.addJob(jobData);
    if (res.success) {
      alert('Job posted successfully!');
      navigate('/admin/jobs');
    } else {
      alert(res.message || 'Failed to post job');
    }
    setIsSubmitting(false);
  };

  /* NeST NAVY BLUE */
  const nestNavy = '#1a2652';

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
      <div>
        <h1 style={{ fontSize: '24px', fontWeight: 800, color: '#1e293b', margin: 0 }}>Post a Job</h1>
      </div>

      <form onSubmit={handleSubmit} style={{ background: '#fff', borderRadius: '16px', border: '1px solid #e2e8f0', overflow: 'hidden' }}>
        <div style={{ padding: '24px', borderBottom: '1px solid #e2e8f0', display: 'flex', alignItems: 'center', gap: '16px' }}>
          <div style={{ background: '#eff6ff', color: '#2563eb', padding: '16px', borderRadius: '16px' }}>
            <ClipboardSignature size={32} />
          </div>
          <div>
            <h2 style={{ fontSize: '20px', fontWeight: 700, color: '#1e293b', margin: 0 }}>Job Details</h2>
            <p style={{ color: '#64748b', fontSize: '14px', marginTop: '4px' }}>Fill out the details to create a new recruitment listing.</p>
          </div>
        </div>

        <div style={{ padding: '24px', display: 'flex', flexDirection: 'column', gap: '20px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '24px' }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <label style={{ fontSize: '14px', fontWeight: 600, color: '#475569' }}>Job Title</label>
              <input 
                required
                type="text" 
                placeholder="e.g. Senior Java Developer" 
                value={formData.title}
                onChange={e => setFormData({...formData, title: e.target.value})}
                style={{ padding: '12px 16px', borderRadius: '10px', border: '1px solid #e2e8f0', outline: 'none' }} 
              />
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <label style={{ fontSize: '14px', fontWeight: 600, color: '#475569' }}>Company</label>
              <input 
                required
                type="text" 
                placeholder="e.g. NeST Digital" 
                value={formData.company}
                onChange={e => setFormData({...formData, company: e.target.value})}
                style={{ padding: '12px 16px', borderRadius: '10px', border: '1px solid #e2e8f0', outline: 'none' }} 
              />
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '24px' }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <label style={{ fontSize: '14px', fontWeight: 600, color: '#475569' }}>Location</label>
              <input 
                required
                type="text" 
                placeholder="e.g. Kochi, Kerala" 
                value={formData.location}
                onChange={e => setFormData({...formData, location: e.target.value})}
                style={{ padding: '12px 16px', borderRadius: '10px', border: '1px solid #e2e8f0', outline: 'none' }} 
              />
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <label style={{ fontSize: '14px', fontWeight: 600, color: '#475569' }}>Salary Range</label>
              <input 
                type="text" 
                placeholder="e.g. 5L - 8L PA" 
                value={formData.salary}
                onChange={e => setFormData({...formData, salary: e.target.value})}
                style={{ padding: '12px 16px', borderRadius: '10px', border: '1px solid #e2e8f0', outline: 'none' }} 
              />
            </div>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            <label style={{ fontSize: '14px', fontWeight: 600, color: '#475569' }}>Job Description</label>
            <textarea 
              required
              rows={4}
              placeholder="Describe the role and responsibilities..." 
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
              style={{ padding: '12px 16px', borderRadius: '10px', border: '1px solid #e2e8f0', outline: 'none', resize: 'vertical' }} 
            />
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            <label style={{ fontSize: '14px', fontWeight: 600, color: '#475569' }}>Requirements (One per line)</label>
            <textarea 
              rows={4}
              placeholder="e.g. 3+ years experience in React&#10;Strong understanding of Node.js" 
              value={formData.requirements}
              onChange={e => setFormData({...formData, requirements: e.target.value})}
              style={{ padding: '12px 16px', borderRadius: '10px', border: '1px solid #e2e8f0', outline: 'none', resize: 'vertical' }} 
            />
          </div>
        </div>

        <div style={{ padding: '24px', borderTop: '1px solid #e2e8f0', display: 'flex', justifyContent: 'flex-end', gap: '12px', background: '#f8fafc' }}>
          <button 
            type="button"
            onClick={() => navigate('/admin/jobs')}
            style={{ padding: '12px 24px', borderRadius: '10px', background: '#fff', color: '#475569', fontWeight: 600, border: '1px solid #e2e8f0', cursor: 'pointer' }}
          >
            Cancel
          </button>
          <button 
            disabled={isSubmitting}
            type="submit"
            style={{ padding: '12px 24px', borderRadius: '10px', background: '#2563eb', color: '#fff', fontWeight: 600, border: 'none', cursor: 'pointer', opacity: isSubmitting ? 0.7 : 1 }}
          >
            {isSubmitting ? 'Posting...' : 'Post Job'}
          </button>
        </div>
      </form>
    </div>
  );
};

